import re, hashlib

# Patterns to strip before any logging
_CONFIDENTIAL_PATTERNS = [
    r'\b[A-Z][a-z]+ [A-Z][a-z]+\b',       # named entities (rudimentary)
    r'\$\d[\d,]*(?:\.\d{2})?',            # dollar amounts
    r'\b(?:Project|Deal|Merger)\s+\w+\b', # deal code-names
]

def scrub_for_log(text: str) -> str:
    """Replace confidential patterns with '[REDACTED]' before logging."""
    for pattern in _CONFIDENTIAL_PATTERNS:
        text = re.sub(pattern, "[REDACTED]", text)
    return text

def log_confidential_request(prompt: str, response_text: str):
    record = {
        "prompt_sha256": hashlib.sha256(prompt.encode()).hexdigest(),
        "prompt_preview": scrub_for_log(prompt[:120]),  # first 120 chars, scrubbed
        "response_sha256": hashlib.sha256(response_text.encode()).hexdigest(),
    }
